@import "tailwindcss";

/* ============================================
   GUNMETAL DESIGN SYSTEM
   Inspired by Warp — warm dark, editorial, minimal
   ============================================ */

@layer theme {
  :root {
    /* ----------------------------------------
       COLOR PALETTE — Warp Warm Dark
       Warm near-black canvas, cream parchment text
       Almost monochromatic warm grays
       ---------------------------------------- */

    /* Background — warm near-black, not cold */
    --bg: #0e0e0d;

    /* Surface — warm dark */
    --surface: #181816;
    --surface-elevated: #222220;

    /* Text hierarchy — warm, not pure white */
    --text: #faf9f6;
    --text-secondary: #afaeac;
    --text-muted: #868584;
    --text-faint: #666469;

    /* Borders — semi-transparent warm */
    --border: rgba(226, 226, 226, 0.18);
    --border-strong: rgba(226, 226, 226, 0.35);

    /* Buttons — earthy dark, muted text */
    --btn-bg: #353534;
    --btn-text: #afaeac;
    --btn-border: rgba(255, 255, 255, 0.08);
    --btn-hover-bg: #404040;
    --btn-hover-text: #faf9f6;

    /* CTAs — restrained, no bright accents */
    --cta-bg: #faf9f6;
    --cta-text: #0e0e0d;
    --cta-hover-bg: #e8e7e4;

    /* Surface overlays */
    --frosted: rgba(255, 255, 255, 0.04);
    --veil: rgba(255, 255, 255, 0.06);

    /* Grid — barely visible warm lines */
    --grid-color: rgba(255, 255, 255, 0.02);
    --grid-size: 64px;

    /* Font families — Matter-inspired DM Sans + Inter supplement */
    --font-matter: var(--font-dm-sans), -apple-system, BlinkMacSystemFont, sans-serif;
    --font-sans: var(--font-inter), -apple-system, BlinkMacSystemFont, sans-serif;
    --font-mono: var(--font-jetbrains), ui-monospace, monospace;

