    font-family: var(--font-matter);
    font-size: clamp(3.5rem, 10vw, 6rem);
    font-weight: 400;
    line-height: 1.00;
    letter-spacing: -0.03em;
  }

  /* Section heading — 56px Matter */
  .text-section {
    font-family: var(--font-matter);
    font-size: clamp(2rem, 5vw, 3.5rem);
    font-weight: 400;
    line-height: 1.10;
    letter-spacing: -0.02em;
  }

  /* Feature heading — 40px Matter */
  .text-feature {
    font-family: var(--font-matter);
    font-size: clamp(1.75rem, 3vw, 2.5rem);
    font-weight: 400;
    line-height: 1.10;
    letter-spacing: -0.015em;
  }

  /* Card title — 22px Matter Medium */
