    font-size: 1.25rem;
    font-weight: 400;
    line-height: 1.40;
    letter-spacing: -0.01em;
  }

  /* Body — 18px Matter */
  .text-body {
    font-family: var(--font-matter);
    font-size: 1.125rem;
    font-weight: 400;
    line-height: 1.50;
    letter-spacing: -0.01em;
