.btn-pill {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  gap: 8px;
  padding: 10px 20px;
  background: var(--btn-bg);
  color: var(--btn-text);
  border: 1px solid var(--btn-border);
  border-radius: var(--radius-pill);
  font-family: var(--font-matter);
  font-size: 0.9375rem;
  font-weight: 400;
  letter-spacing: 0;
  cursor: pointer;
  transition: all var(--duration-fast) var(--ease-out);
  white-space: nowrap;
}

.btn-pill:hover {
  background: var(--btn-hover-bg);
  color: var(--btn-hover-text);
}

/* CTA pill — light, on dark */
.btn-cta {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  gap: 8px;
  padding: 12px 24px;
  background: var(--cta-bg);
  color: var(--cta-text);
  border: 1px solid transparent;
  border-radius: var(--radius-pill);
  font-family: var(--font-matter);
  font-size: 0.9375rem;
  font-weight: 400;
  letter-spacing: 0;
  cursor: pointer;
  transition: all var(--duration-fast) var(--ease-out);
  white-space: nowrap;
}

.btn-cta:hover {
  background: var(--cta-hover-bg);
}

/* Ghost pill — border only */
.btn-ghost {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  gap: 8px;
  padding: 12px 24px;
  background: transparent;
  color: var(--text-secondary);
  border: 1px solid var(--border-strong);
  border-radius: var(--radius-pill);
  font-family: var(--font-matter);
  font-size: 0.9375rem;
  font-weight: 400;
  letter-spacing: 0;
  cursor: pointer;
  transition: all var(--duration-fast) var(--ease-out);
  white-space: nowrap;
}

.btn-ghost:hover {
  color: var(--text);
  border-color: rgba(226, 226, 226, 0.55);
}

/* Cursor blink */
.cursor {
  display: inline-block;
  width: 2px;
  height: 1.1em;
  background: var(--text-secondary);
  margin-left: 1px;
  vertical-align: text-bottom;
  animation: blink 1s step-end infinite;
}

/* Status dot */
.status-dot {
  position: relative;
  display: inline-block;
  width: 6px;
  height: 6px;
  border-radius: 50%;
  background: var(--text-muted);
}

.status-dot::before {
  content: "";
  position: absolute;
  inset: 0;
  border-radius: 50%;
  background: var(--text-secondary);
  animation: pulse-ring 2s ease-out infinite;
}

